        "validate_invoice",
        "check_approval_threshold", 
        "process_payment",
        "send_confirmation"
    ])
])
def verified_workflow(task):
    return hub.run(task)

# Verifies sequence matches expected workflow
result = verified_workflow("Process invoice workflow")

@verify([
    Policy.permissions(required_scopes=["payment:write", "crm:read"]),
    Policy.idempotency(check_keys=["invoice_id", "customer_id"])
])
def safe_api_workflow(invoice_id):
    result = hub.run(f"Process invoice {invoice_id}")
    return result

# Blocks unauthorized access, checks for duplicates
safe_api_workflow("INV-123")

from vex import Policy

@verify([
    Policy.rollback_capable([
        "stripe_charge",
        "hubspot_contact_create"
    ]),
    Policy.state_consistency()
])
def transactional_workflow(invoice):
    operations = []
    try:
        result = hub.run(f"Process {invoice}")
        operations.extend(result['executed_ops'])
        return result
    except Exception:
        # Vex verifies rollback was triggered
        for op in operations:
            hub.run(f"rollback {op}")
        raise
